class Solution {
public:
    int countStudents(vector<int>& students, vector<int>& sandwiches) {
        int ones = 0, zeros = 0;
        for (int student : students) {
            if (student == 1) ones++;
            else zeros++;
        }
        for (int sandwich : sandwiches) {
            if (sandwich == 1) {
                if (ones == 0) return zeros;
                ones--;
            } else {
                if (zeros == 0) return ones;
                zeros--;
            }
        }
        return 0;
    }
};
